import { unstable_cache } from "next/cache";
import { revalidateTag } from "next/cache";
import { waitUntil } from "next/server";
import { getAllProducts } from "@/lib/db";
import { SyncForm } from "./sync-form";

// ---------------------------------------------------------------------------
// Cache product data with the "products" tag so every view that depends on
// the same catalog shares a single cached entry.  This keeps the admin
// experience snappy without re-querying the DB on every pageload.
// ---------------------------------------------------------------------------
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["admin-products-list"],
  { tags: ["products"] },
);

export type SyncResult = {
  success: boolean;
  message: string;
};

// ---------------------------------------------------------------------------
// Admin product catalog page
// ---------------------------------------------------------------------------
export default async function AdminProductsPage() {
  let products: Awaited<ReturnType<typeof getAllProducts>> | null = null;
  let error: string | null = null;

  try {
    products = await getCachedProducts();
  } catch {
    error = "Failed to load products. Please try again.";
  }

  // -----------------------------------------------------------------------
  // Inline Server Action — triggers a background catalog sync.
  //
  // The admin gets an immediate response without waiting for the sync to
  // finish.  Once the background work completes, the "products" cache tag
  // is invalidated so subsequent requests pick up the fresh data.
  // -----------------------------------------------------------------------
  async function syncCatalog(
    _prevState: SyncResult | null,
    _formData: FormData,
  ): Promise<SyncResult> {
    "use server";

    try {
      // Defer the heavy sync work so we can reply to the admin right away.
      // waitUntil extends the serverless-function lifetime to allow the
      // background operation to finish after the HTTP response is sent.
      waitUntil(
        (async () => {
          // --- simulated ERP/PIM sync ------------------------------------
          // In production this would pull pricing, inventory, and availability
          // from the upstream system, which can take several seconds for
          // thousands of SKUs.
          await new Promise((resolve) => setTimeout(resolve, 3_000));

          // Invalidate every cache entry tagged "products" so all views
          // (product list, detail pages, search, etc.) eventually converge
          // on the fresh data.
          revalidateTag("products");
        })(),
      );

      return {
        success: true,
        message:
          "Catalog sync has been triggered and will be available shortly.",
      };
    } catch {
      return {
        success: false,
        message: "Failed to start catalog sync. Please try again.",
      };
    }
  }

  // -----------------------------------------------------------------------
  // Render
  // -----------------------------------------------------------------------
  return (
    <div style={{ maxWidth: 960, margin: "0 auto", padding: "2rem 1rem" }}>
      {/* ---- Header ---- */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          flexWrap: "wrap",
          gap: "1rem",
          marginBottom: "2rem",
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: "1.75rem" }}>Product Catalog</h1>
          <p style={{ margin: "0.25rem 0 0", color: "#666" }}>
            Browse and manage product data. Cached for fast access.
          </p>
        </div>

        <SyncForm syncAction={syncCatalog} />
      </div>

      {/* ---- Error banner ---- */}
      {error && (
        <div
          style={{
            padding: "0.75rem 1rem",
            marginBottom: "1rem",
            background: "#fef2f2",
            border: "1px solid #fecaca",
            borderRadius: 6,
            color: "#b91c1c",
            fontSize: "0.875rem",
          }}
        >
          {error}
        </div>
      )}

      {/* ---- Product table ---- */}
      <div style={{ overflowX: "auto" }}>
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            fontSize: "0.875rem",
          }}
        >
          <thead>
            <tr
              style={{
                background: "#f9fafb",
                borderBottom: "2px solid #e5e7eb",
              }}
            >
              <th
                style={{
                  textAlign: "left",
                  padding: "0.75rem 1rem",
                  fontWeight: 600,
                  color: "#374151",
                }}
              >
                SKU
              </th>
              <th
                style={{
                  textAlign: "left",
                  padding: "0.75rem 1rem",
                  fontWeight: 600,
                  color: "#374151",
                }}
              >
                Product Name
              </th>
              <th
                style={{
                  textAlign: "right",
                  padding: "0.75rem 1rem",
                  fontWeight: 600,
                  color: "#374151",
                }}
              >
                Price
              </th>
            </tr>
          </thead>
          <tbody>
            {/* ---- Empty state ---- */}
            {products && products.length === 0 && (
              <tr>
                <td
                  colSpan={3}
                  style={{
                    textAlign: "center",
                    padding: "3rem 1rem",
                    color: "#9ca3af",
                  }}
                >
                  No products found. Sync the catalog to load product data.
                </td>
              </tr>
            )}

            {/* ---- Product rows ---- */}
            {products?.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: "1px solid #e5e7eb" }}
              >
                <td
                  style={{
                    padding: "0.75rem 1rem",
                    color: "#6b7280",
                    fontVariantNumeric: "tabular-nums",
                  }}
                >
                  {product.id}
                </td>
                <td style={{ padding: "0.75rem 1rem", fontWeight: 500 }}>
                  {product.name}
                </td>
                <td
                  style={{
                    padding: "0.75rem 1rem",
                    textAlign: "right",
                    fontVariantNumeric: "tabular-nums",
                  }}
                >
                  ${product.price}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

"use client";

import { useActionState } from "react";
import { useFormStatus } from "react-dom";
import type { SyncResult } from "./page";

// ---------------------------------------------------------------------------
// Submit button — uses useFormStatus to show a pending spinner while the
// server action is in flight.  The button is disabled during submission to
// prevent accidental double-clicks / double-syncs.
// ---------------------------------------------------------------------------
function SubmitButton() {
  const { pending } = useFormStatus();

  return (
    <button
      type="submit"
      disabled={pending}
      style={{
        padding: "0.5rem 1rem",
        background: pending ? "#9ca3af" : "#2563eb",
        color: "#fff",
        border: "none",
        borderRadius: 6,
        cursor: pending ? "not-allowed" : "pointer",
        fontWeight: 500,
        fontSize: "0.875rem",
        display: "inline-flex",
        alignItems: "center",
        gap: "0.5rem",
        transition: "background 0.15s",
      }}
    >
      {pending && <Spinner />}
      {pending ? "Syncing…" : "Sync latest catalog"}
    </button>
  );
}

// ---------------------------------------------------------------------------
// Tiny inline SVG spinner — avoids any external dependency.
// ---------------------------------------------------------------------------
function Spinner() {
  return (
    <span style={{ display: "inline-block", width: 14, height: 14 }}>
      <svg viewBox="0 0 24 24" fill="none">
        <circle
          cx="12"
          cy="12"
          r="10"
          stroke="currentColor"
          strokeWidth="4"
          opacity="0.25"
        />
        <path
          d="M12 2a10 10 0 0 1 9.95 9"
          stroke="currentColor"
          strokeWidth="4"
          strokeLinecap="round"
        />
      </svg>
      <style>{`svg { animation: spin 1s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </span>
  );
}

// ---------------------------------------------------------------------------
// SyncForm
//
// A client component that wraps the inline server action in useActionState so
// we can show a success / error message right on the form without a full-page
// navigation or client-side state management.
// ---------------------------------------------------------------------------
export function SyncForm({
  syncAction,
}: {
  syncAction: (
    prev: SyncResult | null,
    form: FormData,
  ) => Promise<SyncResult>;
}) {
  const [state, formAction] = useActionState(syncAction, null);

  return (
    <div>
      <form action={formAction}>
        <SubmitButton />
      </form>

      {/* ---- Inline feedback ---- */}
      {state && (
        <p
          style={{
            margin: "0.5rem 0 0",
            fontSize: "0.8125rem",
            color: state.success ? "#16a34a" : "#dc2626",
          }}
        >
          {state.message}
        </p>
      )}
    </div>
  );
}

