import { unstable_cache, revalidateTag } from "next/cache";
import { getAllProducts } from "@/lib/db";
import { SyncForm } from "./sync-form";

// ---------------------------------------------------------------------------
// Cache product data with the "products" tag so every view that depends on
// the same catalog shares a single cached entry.  This keeps the admin
// experience snappy without re-querying the DB on every pageload.
// ---------------------------------------------------------------------------
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["admin-products-list"],
  { tags: ["products"] },
);

export type SyncResult = {
  success: boolean;
  message: string;
};

// ---------------------------------------------------------------------------
// Admin product catalog page
// ---------------------------------------------------------------------------
export default async function AdminProductsPage() {
  let products: Awaited<ReturnType<typeof getAllProducts>> | null = null;
  let error: string | null = null;

  try {
    products = await getCachedProducts();
  } catch {
    error = "Failed to load products. Please try again.";
  }

  // -------------------------------------------------------------------------
  // Inline Server Action — triggers a background catalog sync.
  //
  // The admin gets an immediate response without waiting for the sync to
  // finish.  Once the background work completes, the "products" cache tag
  // is invalidated so subsequent requests pick up the fresh data.
  // -------------------------------------------------------------------------
  async function syncCatalog(
    _prevState: SyncResult | null,
    _formData: FormData,
  ): Promise<SyncResult> {
    "use server";

    // --- Kick off the sync without awaiting it ------------------------------
    // The admin gets an immediate response while the revalidation runs in
    // the background.  On the next page load / view that reads from the
    // "products" tag, the cache will have been invalidated and fresh data
    // is fetched.  This gives us eventual consistency across all views
    // without blocking the admin's workflow.
    //
    // In production the async work would pull pricing, inventory, and
    // availability from the ERP / PIM system (possibly thousands of SKUs).
    syncAndInvalidate().catch(() => {
      /* background sync failure is logged by the function itself */
    });

    return {
      success: true,
      message:
        "Catalog sync has been triggered and will be available shortly.",
    };
  }

  // -------------------------------------------------------------------------
  // Background job — runs after the server action response is sent so the
  // admin can continue working immediately without blocking on the sync.
  // -------------------------------------------------------------------------
  async function syncAndInvalidate() {
    try {
      // Simulate the time it takes to fetch and process ERP/PIM updates.
      await new Promise((resolve) => setTimeout(resolve, 3_000));

      // Invalidate every cache entry tagged "products" so all views
      // (product list, detail pages, search, etc.) eventually converge
      // on the fresh data.
      revalidateTag("products");
    } catch {
      console.error("Catalog sync failed.");
    }
  }

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------
  return (
    <div style={{ maxWidth: 960, margin: "0 auto", padding: "2rem 1rem" }}>
      {/* ---- Header ---- */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          flexWrap: "wrap",
          gap: "1rem",
          marginBottom: "2rem",
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: "1.75rem" }}>Product Catalog</h1>
          <p style={{ margin: "0.25rem 0 0", color: "#666" }}>
            Browse and manage product data. Cached for fast access.
          </p>
        </div>

        <SyncForm syncAction={syncCatalog} />
      </div>

      {/* ---- Error banner ---- */}
      {error && (
        <div
          style={{
            padding: "0.75rem 1rem",
            marginBottom: "1rem",
            background: "#fef2f2",
            border: "1px solid #fecaca",
            borderRadius: 6,
            color: "#b91c1c",
            fontSize: "0.875rem",
          }}
        >
          {error}
        </div>
      )}

      {/* ---- Product table ---- */}
      <div style={{ overflowX: "auto" }}>
        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            fontSize: "0.875rem",
          }}
        >
          <thead>
            <tr
              style={{
                background: "#f9fafb",
                borderBottom: "2px solid #e5e7eb",
              }}
            >
              <th
                style={{
                  textAlign: "left",
                  padding: "0.75rem 1rem",
                  fontWeight: 600,
                  color: "#374151",
                }}
              >
                SKU
              </th>
              <th
                style={{
                  textAlign: "left",
                  padding: "0.75rem 1rem",
                  fontWeight: 600,
                  color: "#374151",
                }}
              >
                Product Name
              </th>
              <th
                style={{
                  textAlign: "right",
                  padding: "0.75rem 1rem",
                  fontWeight: 600,
                  color: "#374151",
                }}
              >
                Price
              </th>
            </tr>
          </thead>
          <tbody>
            {/* ---- Empty state ---- */}
            {products && products.length === 0 && (
              <tr>
                <td
                  colSpan={3}
                  style={{
                    textAlign: "center",
                    padding: "3rem 1rem",
                    color: "#9ca3af",
                  }}
                >
                  No products found. Sync the catalog to load product data.
                </td>
              </tr>
            )}

            {/* ---- Product rows ---- */}
            {products?.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: "1px solid #e5e7eb" }}
              >
                <td
                  style={{
                    padding: "0.75rem 1rem",
                    color: "#6b7280",
                    fontVariantNumeric: "tabular-nums",
                  }}
                >
                  {product.id}
                </td>
                <td style={{ padding: "0.75rem 1rem", fontWeight: 500 }}>
                  {product.name}
                </td>
                <td
                  style={{
                    padding: "0.75rem 1rem",
                    textAlign: "right",
                    fontVariantNumeric: "tabular-nums",
                  }}
                >
                  ${product.price}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

